-- V5: Align canonical machine codes with PLC simulator codes for SQL Server
UPDATE machines
SET code = CASE id
    WHEN 'a1000000-0000-0000-0000-000000000001' THEN 'CNC-01'
    WHEN 'a1000000-0000-0000-0000-000000000002' THEN 'CNC-02'
    WHEN 'a1000000-0000-0000-0000-000000000003' THEN 'ROB-01'
    WHEN 'a1000000-0000-0000-0000-000000000004' THEN 'LATHE-01'
    WHEN 'a1000000-0000-0000-0000-000000000005' THEN 'DRILL-01'
    ELSE code
END,
updated_at = SYSUTCDATETIME()
WHERE id IN (
    'a1000000-0000-0000-0000-000000000001',
    'a1000000-0000-0000-0000-000000000002',
    'a1000000-0000-0000-0000-000000000003',
    'a1000000-0000-0000-0000-000000000004',
    'a1000000-0000-0000-0000-000000000005'
)
AND code <> CASE id
    WHEN 'a1000000-0000-0000-0000-000000000001' THEN 'CNC-01'
    WHEN 'a1000000-0000-0000-0000-000000000002' THEN 'CNC-02'
    WHEN 'a1000000-0000-0000-0000-000000000003' THEN 'ROB-01'
    WHEN 'a1000000-0000-0000-0000-000000000004' THEN 'LATHE-01'
    WHEN 'a1000000-0000-0000-0000-000000000005' THEN 'DRILL-01'
    ELSE code
END;

